%[text] ## Creating IIR Filters
%[text] 
fs = single(8e3);
T = 1/16;
t = (-T/2):1/fs:(T/2 -1/fs);

fc_low  = fs/6;
fc_high = 2*fs/6; 

lp = load("lp.mat");
hp = load("hp.mat");
bp = load("bp.mat");

x = single(chirp(t,0,t(end),fs/2));

y_lp = sosfilt(lp.SOS,x)*prod(lp.G);
y_bp = sosfilt(bp.SOS,x)*prod(bp.G);
y_hp = sosfilt(hp.SOS,x)*prod(hp.G);

figure %[output:66cbea58]
subplot(4,1,1) %[output:66cbea58]
plot(x) %[output:66cbea58]
title("Input") %[output:66cbea58]
subplot(4,1,2) %[output:66cbea58]
plot(abs(fft(x))) %[output:66cbea58]
title("Input FFT") %[output:66cbea58]

xlim([0,fs/2]); %[output:66cbea58]
subplot(4,1,3) %[output:66cbea58]
plot(abs(fft(y_lp))) %[output:66cbea58]
title("Lowpass FFT") %[output:66cbea58]
xlim([0,fs/2]); %[output:66cbea58]
subplot(4,1,4) %[output:66cbea58]
plot(y_lp) %[output:66cbea58]
title("Lowpass Output") %[output:66cbea58]

x_pwr = 10*log10(bandpower(x));

figure
sgtitle("Filter Performance")

subplot(4,1,1)
plot(10*log10(abs(fft(x,fs))));
xlim([0, fs/2])
ax = gca;
xline(ax,(fs/2)/3)
xline(ax,2*(fs/2)/3)
yline(gca,x_pwr);

title("Input")

subplot(4,1,2)
plot(10*log10(abs(fft(y_lp,fs))));
ax = gca;
xlim([0, fs/2])
xline(ax,(fs/2)/3)
xline(ax,2*(fs/2)/3)
yline(gca,x_pwr);
title("Low Pass")

subplot(4,1,3)
plot(10*log10(abs(fft(y_bp,fs))));
ax = gca;
xlim([0, fs/2])
xline(ax,(fs/2)/3)
xline(ax,2*(fs/2)/3)
yline(gca,x_pwr);
title("Band Pass")

subplot(4,1,4)
plot(10*log10(abs(fft(y_hp,fs))));
ax = gca;
xlim([0, fs/2])
xline(ax,(fs/2)/3)
xline(ax,2*(fs/2)/3)
yline(gca,x_pwr);
title("High Pass")

% Manual implementation

% Create an internal TDL corresponding to each SOS section
% For each x in: Loop through each SOS on TDL
% Try 1: multiplying by G within loop
% Try 2: Mult by G at end


% TDL -> n=0,n=-1, n=-2

tdl = zeros(3,1+size(lp.SOS, 1));
y_lp_man = zeros(1,length(x));

for xit = 1:length(x)
    tdl(1,1) = x(xit);

    for sosit = 1:size(lp.SOS, 1)
        % x is tdl(:,sosit - 1), y is tdl(:,sosit)
        % -> x[n] = tdl(1,sosit-1), y[n-1] = tdl(2, sosit)
        sos = lp.SOS(sosit,:);
        x_sos = tdl(:,sosit);
        y_sos = tdl(2:end,sosit+1);

        % each sos filter is one row in filt.SOS
        % H -> [b0, b1, b2, 1, a1, a2]
        % difference equation is therefore:
        % y[n] = b0x[n] + b1x[n-1] + b2x[n-2] -a1y[n-1] - a2y[n-2]
        tdl(1,sosit+1) = sum(x_sos'.*sos(1:3))- sum(y_sos'.*sos(5:end));        
    end
    y_lp_man(xit) = tdl(1,end);
    tdl = [ zeros(1,1+size(lp.SOS, 1))
            tdl(1:(end-1), :)
            ];
end

y_lp_man = y_lp_man*prod(lp.G);


figure %[output:7356aef9]
subplot(6,1,1) %[output:7356aef9]
plot(x) %[output:7356aef9]
title("") %[output:7356aef9]
subplot(6,1,2) %[output:7356aef9]
plot(abs(fft(x,fs))) %[output:7356aef9]
xlim([0,fs/2]); %[output:7356aef9]
subplot(6,1,3) %[output:7356aef9]
plot(abs(fft(y_lp,fs))) %[output:7356aef9]
xlim([0,fs/2]); %[output:7356aef9]
subplot(6,1,4) %[output:7356aef9]
plot(y_lp) %[output:7356aef9]
subplot(6,1,5) %[output:7356aef9]
plot(abs(fft(y_lp_man,fs))) %[output:7356aef9]
xlim([0,fs/2]); %[output:7356aef9]
subplot(6,1,6) %[output:7356aef9]
plot(y_lp_man) %[output:7356aef9]
y_man_mse = mean( (y_lp - y_lp_man).^2 ) %[output:7ab9258b]
save_sos(lp.SOS,lp.G,"lp.h","lp")
save_sos(bp.SOS,bp.G,"bp.h","bp")
save_sos(hp.SOS,hp.G,"hp.h","hp")

save_sig(x,fs,"chirp.h","chirp")

%%
%[text] ## Testing C impl
y_lp_c = readmatrix("lp.csv");
y_bp_c = readmatrix("bp.csv");
y_hp_c = readmatrix("hp.csv");

y_lp_c_mse = mean( (y_lp - y_lp_c).^2 ) %[output:0a06d45f]
y_bp_c_mse = mean( (y_bp - y_bp_c).^2 ) %[output:55fda8e6]
y_hp_c_mse = mean( (y_hp - y_hp_c).^2 ) %[output:3d8f9773]

figure %[output:48dd761f]
subplot(3,1,1) %[output:48dd761f]
plot((y_lp - y_lp_c)) %[output:48dd761f]
subplot(3,1,2) %[output:48dd761f]
plot((y_bp - y_bp_c)) %[output:48dd761f]
subplot(3,1,3) %[output:48dd761f]
plot((y_hp - y_hp_c)) %[output:48dd761f]
figure %[output:01a10847]
subplot(3,2,1) %[output:01a10847]
plot((y_lp_c).*(1/max(y_lp_c))); %[output:01a10847]
subplot(3,2,2) %[output:01a10847]
plot((y_lp)) %[output:01a10847]


subplot(3,2,3) %[output:01a10847]
plot((y_bp_c)) %[output:01a10847]
subplot(3,2,4) %[output:01a10847]
plot((y_bp)) %[output:01a10847]
subplot(3,2,5) %[output:01a10847]
plot((y_hp_c)) %[output:01a10847]
subplot(3,2,6) %[output:01a10847]
plot((y_hp)) %[output:01a10847]

